import { Suspense } from "react";
import { ProfileFormContainer } from "./_components/profile-form.container.server";
import { ProfileFormSkeleton } from "./_components/profile-form.skeleton.universal";

export default function SettingsPage() {
  return (
    <div className="mx-auto max-w-2xl px-4 py-8">
      <h1 className="mb-8 text-xl font-bold text-foreground">プロフィール</h1>
      <Suspense fallback={<ProfileFormSkeleton />}>
        <ProfileFormContainer />
      </Suspense>
    </div>
  );
}

